Steps:
[AUTH role=LOYALTY_VIP_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP discover_pts_product]
  query { products(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "@td(LOYALTY_SETTINGS.currency_code)" first: 1 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.@td(LOYALTY_SETTINGS.currency_code):(0 TO)") { items { id } } }
[GQL-EXEC discover_pts_product]
[GQL-CAPTURE discover_pts_product.data.products.items.0.id → PTS_PRODUCT_ID]
[GQL-OP add_usd_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" productId: "@td(BUYABLE_NO_MIN_QTY.id)" quantity: 1 }) { id items { id currencyCode } } }
[GQL-EXEC add_usd_item]
[GQL-OP add_pts_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" productId: "{{PTS_PRODUCT_ID}}" quantity: 1 itemCurrencyCode: "@td(LOYALTY_SETTINGS.currency_code)" }) { id } }
[GQL-EXEC add_pts_item]
[GQL-OP read_pre]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
    itemsCount
    total { amount currency { code } } subTotal { amount } taxTotal { amount }
    shippingPrice { amount } shippingTotal { amount }
    items { id currencyCode selectedForCheckout loyaltyPoints { amount currency { code } } }
    availableShippingMethods { code name optionName price { amount currency { code } } }
    cartTotals { isDefaultTotalCurrency total { amount currency { code } } subTotal { amount } taxTotal { amount } }
  } }
[GQL-EXEC read_pre]
[GQL-CAPTURE read_pre.data.cart.items[?currencyCode=USD].id → USD_LINE_ID]
[GQL-CAPTURE read_pre.data.cart.items[?currencyCode=@td(LOYALTY_SETTINGS.currency_code)].id → PTS_LINE_ID]
[GQL-CAPTURE read_pre.data.cart.availableShippingMethods[?optionName=Ground].code → SHIP_CODE]
[GQL-CAPTURE read_pre.data.cart.availableShippingMethods[?optionName=Ground].optionName → SHIP_OPTION]
[GQL-CAPTURE read_pre.data.cart.availableShippingMethods[?optionName=Ground].price.amount → SHIP_PRICE]
[GQL-OP add_shipment]
  mutation { addOrUpdateCartShipment(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" shipment: { shipmentMethodCode: "{{SHIP_CODE}}" shipmentMethodOption: "{{SHIP_OPTION}}" price: {{SHIP_PRICE}} deliveryAddress: { city: "New York" countryCode: "US" countryName: "United States" firstName: "Test" lastName: "User" line1: "123 Test St" postalCode: "10001" } } }) { id } }
[GQL-EXEC add_shipment]
[GQL-OP read_with_ship]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
    total { amount } subTotal { amount } taxTotal { amount } shippingPrice { amount } shippingTotal { amount }
    shipments { id shipmentMethodCode price { amount } }
  } }
[GQL-EXEC read_with_ship]
[GQL-CAPTURE read_with_ship.data.cart.total.amount → TOTAL_WITH_SHIP]
[GQL-CAPTURE read_with_ship.data.cart.shippingTotal.amount → SHIPTOTAL_WITH_SHIP]
[GQL-OP unselect_usd]
  mutation { unSelectCartItems(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemIds: "{{USD_LINE_ID}}" }) { id } }
[GQL-EXEC unselect_usd]
[GQL-OP unselect_pts]
  mutation { unSelectCartItems(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemIds: "{{PTS_LINE_ID}}" }) { id } }
[GQL-EXEC unselect_pts]
[GQL-OP read_unsel]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
    itemsCount
    total { amount currency { code } } subTotal { amount } taxTotal { amount }
    shippingPrice { amount } shippingTotal { amount }
    items { id currencyCode selectedForCheckout }
    shipments { id shipmentMethodCode price { amount } }
    cartTotals { isDefaultTotalCurrency total { amount currency { code } } subTotal { amount } taxTotal { amount } }
  } }
[GQL-EXEC read_unsel]
[GQL-CAPTURE read_unsel.data.cart.total.amount → TOTAL_UNSEL]
[GQL-CAPTURE read_unsel.data.cart.subTotal.amount → SUBTOTAL_UNSEL]
[GQL-CAPTURE read_unsel.data.cart.taxTotal.amount → TAXTOTAL_UNSEL]
[GQL-CAPTURE read_unsel.data.cart.shippingTotal.amount → SHIPTOTAL_UNSEL]
[GQL-CAPTURE read_unsel.data.cart.shippingPrice.amount → SHIPPRICE_UNSEL]
[GQL-CAPTURE read_unsel.data.cart.cartTotals[?isDefaultTotalCurrency=false].total.amount → PTS_TOTAL_UNSEL]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]
